import java.util.Arrays;

public int centeredAverage(int[] nums) {
    Arrays.sort(nums);
    int sum = 0;
    int count = 0;
    for (int i = 1, j = nums.length - 2; i < j; i++, j--) {
        sum += nums[i];
        count++;
    }
    return sum / count;
}

